parameters.jsCode:
// Group all emails by threadId
const groupedByThread = {};

items.forEach(item => {
  const threadId = item.json.threadId;

  if (!groupedByThread[threadId]) {
    groupedByThread[threadId] = {
      threadId: threadId,
      subject: item.json.subject,
      emails: []
    };
  }

  groupedByThread[threadId].emails.push({
    id: item.json.id,
    date: item.json.date,
    from: item.json.from,
    to: item.json.to,
    subject: item.json.subject,
    text: item.json.text,
    html: item.json.html,
    messageId: item.json.messageId,
    inReplyTo: item.json.inReplyTo || null
  });
});

// Convert to array and format emails
const output = Object.values(groupedByThread).map(thread => {
  // Sort emails by date (chronological order)
  const sortedEmails = thread.emails.sort((a, b) => 
    new Date(a.date) - new Date(b.date)
  );

  // Format as email conversation thread
  const formattedEmails = sortedEmails
    .map(email => {
      const fromAddress = typeof email.from.value === 'object' 
        ? email.from.value[0]?.address 
        : email.from.text;
      const toAddress = typeof email.to.value === 'object'
        ? email.to.value[0]?.address
        : email.to.text;

      return `[${new Date(email.date).toLocaleString()}]
From: ${fromAddress}
To: ${toAddress}
Subject: ${email.subject}

${email.text}`;
    })
    .join('\n\n---\n\n');

  // Simple format (just text content)
  const simpleFormat = sortedEmails
    .map(email => {
      const fromAddress = typeof email.from.value === 'object' 
        ? email.from.value[0]?.address 
        : email.from.text;
      return `From ${fromAddress}:\n${email.text}`;
    })
    .join('\n\n---\n\n');

  // Extract all unique participants
  const participants = new Set();
  sortedEmails.forEach(email => {
    const fromAddr = typeof email.from.value === 'object' 
      ? email.from.value[0]?.address 
      : email.from.text;
    const toAddr = typeof email.to.value === 'object'
      ? email.to.value[0]?.address
      : email.to.text;
    participants.add(fromAddr);
    participants.add(toAddr);
  });

  // Get the latest email details
  const latestEmail = sortedEmails[sortedEmails.length - 1];
  const latestId = latestEmail?.id;
  const latestFrom = latestEmail?.from;
  const latestTo = latestEmail?.to;

  // Get sender email address from latest message
  const sender = typeof latestFrom?.value === 'object' 
    ? latestFrom.value[0]?.address 
    : latestFrom?.text;

  // Get receiver email address from latest message
  const receiver = typeof latestTo?.value === 'object' 
    ? latestTo.value[0]?.address 
    : latestTo?.text;

  return {
    json: {
      threadId: thread.threadId,
      latest_id: latestId,
      sender: sender,
      receiver: receiver,
      subject: thread.subject,
      email_count: sortedEmails.length,
      participants: Array.from(participants),
      emails_array: sortedEmails,
      emails_formatted: formattedEmails,
      emails_simple: simpleFormat,
      first_email_date: sortedEmails[0]?.date,
      last_email_date: latestEmail?.date,
      latest_from: latestFrom,
      latest_to: latestTo
    }
  };
});

return output;

